const upsertAssistantThread = `-- name: UpsertAssistantThread :one
INSERT INTO assistant_threads (
  assistant_id,
  project_id,
  correlation_id,
  chat_id,
  source_kind,
  source_ref_json,
  last_event_at
) VALUES (
  $1,
  $2,
  $3,
  $4,
  $5,
  $6,
  clock_timestamp()
)
ON CONFLICT (project_id, assistant_id, correlation_id) WHERE deleted IS FALSE
DO UPDATE SET
  source_ref_json = EXCLUDED.source_ref_json,
  last_event_at = clock_timestamp(),
  updated_at = clock_timestamp()
RETURNING id
`

type UpsertAssistantThreadParams struct {
	AssistantID   uuid.UUID
	ProjectID     uuid.UUID
	CorrelationID string
	ChatID        uuid.UUID
	SourceKind    string
	SourceRefJson []byte
}

func (q *Queries) UpsertAssistantThread(ctx context.Context, arg UpsertAssistantThreadParams) (uuid.UUID, error) {
	row := q.db.QueryRow(ctx, upsertAssistantThread,
		arg.AssistantID,
		arg.ProjectID,
		arg.CorrelationID,
		arg.ChatID,
		arg.SourceKind,
		arg.SourceRefJson,
	)
	var id uuid.UUID
	err := row.Scan(&id)
	return id, err
}
